import React from 'react';

const About = () => {
  return (
    <section className="about">
      <div className="container">
        <h2>Explore Your Future: Learn Anytime, Succeed Anywhere</h2>
        <div className="about-content">
          <p>
            At Sky States, we're committed to equipping ambitious people with the capability and self-assurance to succeed in today's quick-paced digital environment. Our vision is straightforward—to accelerate your career achievement through industry-specific training, hands-on experience through real-world projects, and mentorship from experienced professionals, all available online for your convenience.
          </p>
          <p>
            Whether you're starting out or want to advance your skills, our courses are carefully crafted to keep you ahead of the game. With emphasis on practical education, individual guidance, and palpable outcomes, we make sure that each student is positioned for success.
          </p>
        </div>
      </div>
    </section>
  );
};

export default About;
